import React, { useState } from 'react';
import { Button, Select, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { hrService } from '../../../services/ns/hrService';
import type { EmployeeDto, PieceRateLedgerRow } from '../../../services/ns/models';
import { formatVnd } from '../../../utils/format';
import styles from '../../../styles/erpPage.module.css';

const MONTH_OPTIONS = Array.from({ length: 12 }, (_, i) => ({ value: String(i + 1), label: `T${i + 1}` }));
const YEAR_OPTIONS = [2025, 2026, 2027].map(y => ({ value: String(y), label: String(y) }));

const SoLuongKhoanPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const now = new Date();
  const [month, setMonth] = useState(now.getMonth() + 1);
  const [year, setYear] = useState(now.getFullYear());
  const [employeeId, setEmployeeId] = useState('');
  const [employees, setEmployees] = useState<EmployeeDto[]>([]);
  const [rows, setRows] = useState<PieceRateLedgerRow[]>([]);
  const [loading, setLoading] = useState(false);

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      hrService.getEmployees({ type: 'PieceRate', isActive: true, pageSize: 200 })
        .then(res => { if (!cancelled) setEmployees(res.items); })
        .catch(() => {});
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, []);

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      hrService.getPieceRateLedger({ month, year, employeeId: employeeId || undefined })
        .then(data => { if (!cancelled) setRows(data); })
        .catch(err => {
          if (!cancelled)
            dispatch(addToast({ message: err?.message ?? 'Lỗi tải sổ khoán', type: 'error' }));
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [month, year, employeeId, dispatch]);

  const totalAmount = rows.reduce((s, r) => s + (r.totalAmount ?? 0), 0);

  const handleExport = () => {
    const qs = new URLSearchParams({ month: String(month), year: String(year) });
    if (employeeId) qs.set('employeeId', employeeId);
    const a = document.createElement('a');
    a.href = `${import.meta.env.VITE_API_URL}/hr/piece-rate-ledger/export-excel?${qs}`;
    a.download = `LuongKhoan-T${month}-${year}.xlsx`;
    a.click();
  };

  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}>
        <div className={styles.titleBlock}>
          <h1 className={styles.title}><i className="fas fa-chart-bar" /> Sổ theo dõi sản lượng – lương khoán</h1>
          {rows.length > 0 && <p className={styles.subtitle}>Tổng lương khoán: {formatVnd(totalAmount)}</p>}
        </div>
        <div className={styles.headerActions}>
          <Select value={String(month)} onChange={e => setMonth(Number(e.target.value))} options={MONTH_OPTIONS} size="small" />
          <Select value={String(year)} onChange={e => setYear(Number(e.target.value))} options={YEAR_OPTIONS} size="small" />
          <Select
            value={employeeId}
            onChange={e => setEmployeeId(e.target.value)}
            options={[
              { value: '', label: 'Tất cả NV' },
              ...employees.map(e => ({ value: e.id, label: e.fullName })),
            ]}
            size="small"
          />
          <Button variant="secondary" onClick={handleExport}><i className="fas fa-file-excel" /> Xuất Excel</Button>
        </div>
      </div>

      <div className={styles.tableCard}>
        {loading ? (
          <div className={styles.loading}><i className="fas fa-spinner fa-spin" /> Đang tải...</div>
        ) : rows.length === 0 ? (
          <div className={styles.empty}><i className="fas fa-inbox" /><p>Không có dữ liệu</p></div>
        ) : (
          <div className={styles.tableWrapper}>
            <table className={styles.table}>
              <thead>
                <tr>
                  <th>Nhân viên</th>
                  <th>Công đoạn</th>
                  <th className={styles.colRight}>SL hoàn thành</th>
                  <th className={styles.colRight}>Đơn giá/SP</th>
                  <th className={styles.colRight}>Lương khoán</th>
                </tr>
              </thead>
              <tbody>
                {rows.map((r, i) => (
                  <tr key={`${r.employeeId}-${r.stageName}-${i}`}>
                    <td>{r.employeeName ?? '—'}</td>
                    <td>{r.stageName ?? '—'}</td>
                    <td className={styles.colRight}>{r.totalQty ?? 0}</td>
                    <td className={styles.colRight}>{formatVnd(r.pricePerUnit ?? 0)}</td>
                    <td className={styles.colRight}><strong>{formatVnd(r.totalAmount ?? 0)}</strong></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

export default SoLuongKhoanPage;
